#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        if (N < 3) {
            printf("0\n");
        } else {
            printf("%lld\n", (long long)N*(N-1)*(N-2) + (long long)N*(N-1)*(N-2)*(N-3) + (long long)N*(N-1) + (long long)N*(N-1)*(N-2) + (long long)N*(N-1)*(N-2)*(N-3));
        }
    }
    return 0;
}

